function generateUniqueId() { return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (function (t) { const e = 16 * Math.random() | 0; return ("x" === t ? e : 3 & e | 8).toString(16) })) } async function getIP() { try { const t = await fetch("https://ipapi.co/json"); if (!t.ok) throw new Error(`HTTP error! status: ${t.status}`); return await t.json() } catch (t) { throw t } } async function sha256(t) { const e = await crypto.subtle.digest("SHA-256", (new TextEncoder).encode(t)); return Array.from(new Uint8Array(e)).map((t => t.toString(16).padStart(2, "0"))).join("") } async function trackVisitor(t, e) { let n = await getIP(), a = await navigator.getBattery(), o = { userAgent: navigator.userAgent, vendor: navigator.vendor, os: navigator.platform, ip: n.ip, as: n.asn, isp: n.org, city: n.city, batteryLevel: 100 * a.level }; fetch("https://count.spairum.my.id./api/counter/view", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ uid: e, url: t, visitorInfo: o }) }) } let getHostname = new URL(window.location); async function getVisitorId() { const t = getHostname.hostname; let e = await sha256(t), n = localStorage.getItem(e); return n || (n = generateUniqueId(), localStorage.setItem(e, n)), n } async function cekSessi() { let t = `${getHostname.hostname}${getHostname.pathname}`; if (!sessionStorage.getItem(t)) { const e = await getVisitorId(); trackVisitor(t, e), sessionStorage.setItem(t, e) } } cekSessi();